cat > src/calculations.js << 'EOF'
function compoundInterest(principal, rate, years) {
  return principal * Math.pow(1 + rate, years);
}

function variance(data) {
  const mean = data.reduce((a, b) => a + b) / data.length;
  const squaredDiffs = data.map(x => Math.pow(x - mean, 2));
  return squaredDiffs.reduce((a, b) => a + b) / data.length;
}

function loanPayment(principal, monthlyRate, months) {
  if (monthlyRate === 0) return principal / months;
  const powerTerm = Math.pow(1 + monthlyRate, months);
  return principal * (monthlyRate * powerTerm) / (powerTerm - 1);
}

function add(a, b) {
  return a + b;
}

module.exports = {
  compoundInterest,
  variance,
  loanPayment,
  add
};
EOF
